import java.util.PriorityQueue;

public int minimumSize(int[] nums, int maxOperations) {
    PriorityQueue<Integer> pq = new PriorityQueue<>((a, b) -> b - a);
    for (int num : nums) {
        pq.offer(num);
    }
    while (maxOperations > 0) {
        int maxBalls = pq.poll();
        pq.offer(maxBalls / 2);
        pq.offer(maxBalls - (maxBalls / 2));
        maxOperations--;
    }
    return pq.peek();
}
```

